```class Solution {
public:
    long long maximumTripletValue(vector<int>& nums) {
        int n = nums.size();
        long long maxValue = 0;

        for (int i = 0; i < n - 2; i++) {
            for (int j = i + 1; j < n - 1; j++) {
                for (int k = j + 1; k < n; k++) {
                    maxValue = max(max(max(nums[i] - nums[j], nums[j] - nums[k]), nums[i] * nums[k]);
                }
            }
        }
        return maxValue;
    }
};```

